module alu(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);

    // Internal signals
    wire [31:0] add_result;
    wire [31:0] sub_result;
    wire [31:0] and_result;
    wire [31:0] or_result;
    wire [31:0] xor_result;
    wire [31:0] nor_result;
    wire [31:0] slt_result;
    wire [31:0] sltu_result;
    wire [31:0] sll_result;
    wire [31:0] srl_result;
    wire [31:0] sra_result;
    wire [31:0] lui_result;

    // ALU operations
    assign add_result = a + b;
    assign sub_result = a - b;
    assign and_result = a & b;
    assign or_result = a | b;
    assign xor_result = a ^ b;
    assign nor_result = ~(a | b);
    assign slt_result = $signed(a) < $signed(b) ? 32'd1 : 32'd0;
    assign sltu_result = a < b ? 32'd1 : 32'd0;
    assign sll_result = a << b[4:0];
    assign srl_result = a >> b[4:0];
    assign sra_result = $signed(a) >>> b[4:0];
    assign lui_result = {b[15:0], 16'd0};

    // Output multiplexer
    assign r = (aluc == 6'b000000) ? add_result :
               (aluc == 6'b000001) ? sub_result :
               (aluc == 6'b000010) ? and_result :
               (aluc == 6'b000011) ? or_result :
               (aluc == 6'b000100) ? xor_result :
               (aluc == 6'b000101) ? nor_result :
               (aluc == 6'b000110) ? slt_result :
               (aluc == 6'b000111) ? sltu_result :
               (aluc == 6'b001000) ? sll_result :
               (aluc == 6'b001001) ? srl_result :
               (aluc == 6'b001010) ? sra_result :
               (aluc == 6'b001011) ? lui_result : 32'd0;

    // Flags
    assign zero = (r == 32'd0);
    assign carry = (aluc == 6'b000000) && (add_result[32] == 1'b1);
    assign negative = (aluc == 6'b000000) && (add_result[31] == 1'b1);
    assign overflow = (aluc == 6'b000000) && ((a[31] == b[31]) && (a[31] != add_result[31]));
    assign flag = (aluc == 6'b000110) ? slt_result[0] : (aluc == 6'b000111) ? sltu_result[0] : 1'b0;

endmodule
